mapper.select:
SELECT rs.reservation_id, rs.reservation_no, rs.patient_id, p.name AS patient_name, rs.department_id, d.department_name AS department_name, rs.doctor_id, doc.full_name AS doctor_name, rs.reserved_at, rs.status, rs.note, NVL(rs.is_active, 1) AS is_active, rs.inactive_at, rs.inactive_reason_code, rs.inactive_reason_text, rs.canceled_at, rs.cancel_reason_code, rs.cancel_reason_text, rs.created_by, rs.updated_by, rs.created_at, rs.updated_at FROM RESERVATION rs LEFT JOIN patient p ON p.patient_id = rs.patient_id LEFT JOIN CMH.STAFF_DEPARTMENT d ON d.department_id = TO_CHAR(rs.department_id) LEFT JOIN CMH.STAFF doc ON doc.staff_id = TO_CHAR(rs.doctor_id) AND doc.staff_id LIKE 'DOC-%' AND UPPER(TRIM(NVL(doc.employment_status, 'ACTIVE'))) = 'ACTIVE'
1 = 1
AND rs.reservation_no = #{searchValue}
AND rs.patient_id = #{searchValue}
AND p.name LIKE '%' || #{searchValue} || '%'
AND rs.status = #{searchValue}
ORDER BY rs.reservation_id DESC
